// =============================================================
//  stores/auth.js
//  登录态：token（持久化到 localStorage）+ user 信息
// =============================================================

import { defineStore } from 'pinia'
import { ref, computed } from 'vue'
import { authApi } from '../api/auth'

const TOKEN_KEY = 'chatbox_token'

export const useAuthStore = defineStore('auth', () => {
  const token = ref(localStorage.getItem(TOKEN_KEY) || '')
  const user = ref(null)

  const isLoggedIn = computed(() => !!token.value && !!user.value)

  function setToken(t) {
    token.value = t
    if (t) localStorage.setItem(TOKEN_KEY, t)
    else localStorage.removeItem(TOKEN_KEY)
  }

  // 启动时调一次：如果 token 存在 → 调 /me 拿用户信息
  async function restore() {
    if (!token.value) return
    try {
      const { user: u } = await authApi.me()
      user.value = u
    } catch {
      setToken('')
      user.value = null
    }
  }

  async function login(credentials) {
    const { token: t, user: u } = await authApi.login(credentials)
    setToken(t)
    user.value = u
    return u
  }

  async function register(credentials) {
    const { token: t, user: u } = await authApi.register(credentials)
    setToken(t)
    user.value = u
    return u
  }

  function logout() {
    setToken('')
    user.value = null
  }

  return { token, user, isLoggedIn, restore, login, register, logout }
})

// =============================================================
//  router/index.js
//  路由 + 守卫：未登录 → /login；已登录访问 /login 或 /register → /chat
// =============================================================

import { createRouter, createWebHashHistory } from 'vue-router'
import { useAuthStore } from '../stores/auth'
import { setUnauthorizedHandler } from '../api/request'

const routes = [
  { path: '/',          redirect: '/chat' },
  { path: '/login',     name: 'login',    component: () => import('../views/LoginView.vue'),    meta: { guest: true } },
  { path: '/register',  name: 'register', component: () => import('../views/RegisterView.vue'), meta: { guest: true } },
  { path: '/chat',      name: 'chat',     component: () => import('../views/ChatView.vue'),     meta: { auth: true } },
  { path: '/settings',  name: 'settings', component: () => import('../views/SettingsView.vue'), meta: { auth: true } },
  { path: '/:catchAll(.*)', redirect: '/chat' }
]

const router = createRouter({
  history: createWebHashHistory(),
  routes
})

router.beforeEach((to, _from) => {
  const auth = useAuthStore()
  if (to.meta.auth && !auth.isLoggedIn) return { name: 'login', query: { redirect: to.fullPath } }
  if (to.meta.guest && auth.isLoggedIn) return { name: 'chat' }
})

// 请求拦截器里 401 → 自动跳登录
setUnauthorizedHandler(() => {
  if (router.currentRoute.value.name !== 'login') {
    router.push({ name: 'login' })
  }
})

export default router
